 24→/// Decode tool-call arguments from provider or persisted JSON.
 25→///
 26→/// OpenAI-style APIs typically encode `arguments` as a JSON string, while some
 27→/// compatible backends return native JSON directly. Preserve the native shape
 28→/// when it is already structured and only parse when the payload is a string.
 29→#[must_use]
 30→pub fn decode_tool_call_arguments(arguments: Option<&serde_json::Value>) -> serde_json::Value {
 31→    match arguments {
 32→        Some(serde_json::Value::String(raw)) => serde_json::from_str(raw)
 33→            .unwrap_or_else(|_| serde_json::Value::Object(Default::default())),
 34→        Some(serde_json::Value::Null) | None => serde_json::Value::Object(Default::default()),
 35→        Some(value) => value.clone(),
 36→    }
 37→}
