 20→impl OpenAiProvider {
 21→    /// Stream using the OpenAI Responses API format (`/responses`) over SSE.
 22→    #[allow(clippy::collapsible_if)]
 23→    pub(super) fn stream_responses_sse(
 24→        &self,
 25→        messages: Vec<ChatMessage>,
 26→        tools: Vec<serde_json::Value>,
 27→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
 28→        Box::pin(async_stream::stream! {
 29→            let (instructions, input) = split_responses_instructions_and_input(messages);
 30→            let mut body = serde_json::json!({
 31→                "model": self.model,
 32→                "input": input,
 33→                "stream": true,
 34→            });
 35→
 36→            if let Some(instructions) = instructions {
 37→                body["instructions"] = serde_json::Value::String(instructions);
 38→            }
 39→
 40→            if !tools.is_empty() {
 41→                body["tools"] = serde_json::Value::Array(to_responses_api_tools(&tools));
 42→                body["tool_choice"] = serde_json::json!("auto");
 43→            }
 44→
 45→            self.apply_reasoning_effort_responses(&mut body);
 46→
 47→            debug!(
 48→                model = %self.model,
 49→                tools_count = tools.len(),
 50→                "openai stream_responses_sse request"
 51→            );
 52→            trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "openai responses stream request body");
 53→
 54→            let url = self.responses_sse_url();
 55→            let resp = match self
 56→                .client
 57→                .post(&url)
 58→                .header("Authorization", format!("Bearer {}", self.api_key.expose_secret()))
 59→                .header("content-type", "application/json")
 60→                .json(&body)
 61→                .send()
 62→                .await
 63→            {
 64→                Ok(r) => {
 65→                    if let Err(e) = r.error_for_status_ref() {
 66→                        let status = e.status().map(|s| s.as_u16()).unwrap_or(0);
 67→                        let retry_after_ms = retry_after_ms_from_headers(r.headers());
 68→                        let body_text = r.text().await.unwrap_or_default();
 69→                        yield StreamEvent::Error(with_retry_after_marker(
 70→                            format!("HTTP {status}: {body_text}"),
 71→                            retry_after_ms,
 72→                        ));
 73→                        return;
 74→                    }
 75→                    r
 76→                }
 77→                Err(e) => {
 78→                    yield StreamEvent::Error(e.to_string());
 79→                    return;
 80→                }
 81→            };
 82→
 83→            let mut byte_stream = resp.bytes_stream();
 84→            let mut buf = String::new();
 85→            let mut state = ResponsesStreamState::default();
 86→            let mut stream_done = false;
 87→
 88→            while let Some(chunk) = byte_stream.next().await {
 89→                let chunk = match chunk {
 90→                    Ok(c) => c,
 91→                    Err(e) => {
 92→                        yield StreamEvent::Error(e.to_string());
 93→                        return;
 94→                    }
 95→                };
 96→                buf.push_str(&String::from_utf8_lossy(&chunk));
 97→
 98→                while let Some(pos) = buf.find('\n') {
 99→                    let line = buf[..pos].trim().to_string();
100→                    buf = buf[pos + 1..].to_string();
101→
102→                    if line.is_empty() {
103→                        continue;
104→                    }
105→
106→                    let Some(data) = line
107→                        .strip_prefix("data: ")
108→                        .or_else(|| line.strip_prefix("data:"))
109→                    else {
110→                        // Handle bare event types (e.g. "event: response.completed")
111→                        continue;
112→                    };
113→
114→                    match process_responses_sse_line(data, &mut state) {
115→                        SseLineResult::Done => {
116→                            stream_done = true;
117→                            break;
118→                        }
119→                        SseLineResult::Events(events) => {
120→                            for event in events {
121→                                yield event;
122→                            }
123→                        }
124→                        SseLineResult::Skip => {}
125→                    }
126→                }
127→                if stream_done {
128→                    break;
129→                }
130→            }
131→
132→            // Process any residual buffered line on EOF.
133→            if !stream_done {
134→                let line = buf.trim().to_string();
135→                if !line.is_empty()
136→                    && let Some(data) = line
137→                        .strip_prefix("data: ")
138→                        .or_else(|| line.strip_prefix("data:"))
139→                {
140→                    match process_responses_sse_line(data, &mut state) {
141→                        SseLineResult::Done | SseLineResult::Skip => {}
142→                        SseLineResult::Events(events) => {
143→                            for event in events {
144→                                yield event;
145→                            }
146→                        }
147→                    }
148→                }
149→            }
150→
151→            // Finalize: emit pending ToolCallComplete events + Done with usage.
152→            for event in finalize_responses_stream(&mut state) {
153→                yield event;
154→            }
155→        })
156→    }
