158→    #[allow(clippy::collapsible_if)]
159→    pub(super) fn stream_with_tools_sse(
160→        &self,
161→        messages: Vec<ChatMessage>,
162→        tools: Vec<serde_json::Value>,
163→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
164→        Box::pin(async_stream::stream! {
165→            let mut openai_messages = self.serialize_messages_for_request(&messages);
166→            self.apply_openrouter_cache_control(&mut openai_messages);
167→            let mut body = serde_json::json!({
168→                "model": self.model,
169→                "messages": openai_messages,
170→                "stream": true,
171→                "stream_options": { "include_usage": true },
172→            });
173→            self.apply_system_prompt_rewrite(&mut body);
174→
175→            if !tools.is_empty() {
176→                body["tools"] =
177→                    serde_json::Value::Array(to_openai_tools(&tools, self.needs_strict_tools()));
178→            }
179→
180→            self.apply_reasoning_effort_chat(&mut body);
181→
182→            debug!(
183→                model = %self.model,
184→                messages_count = openai_messages.len(),
185→                tools_count = tools.len(),
186→                reasoning_effort = ?self.reasoning_effort,
187→                "openai stream_with_tools request (sse)"
188→            );
189→            trace!(body = %serde_json::to_string(&body).unwrap_or_default(), "openai stream request body (sse)");
190→
191→            let resp = match self
192→                .client
193→                .post(format!("{}/chat/completions", self.base_url))
194→                .header("Authorization", format!("Bearer {}", self.api_key.expose_secret()))
195→                .header("content-type", "application/json")
196→                .json(&body)
197→                .send()
198→                .await
199→            {
200→                Ok(r) => {
201→                    if let Err(e) = r.error_for_status_ref() {
202→                        let status = e.status().map(|s| s.as_u16()).unwrap_or(0);
203→                        let retry_after_ms = retry_after_ms_from_headers(r.headers());
204→                        let body_text = r.text().await.unwrap_or_default();
205→                        yield StreamEvent::Error(with_retry_after_marker(
206→                            format!("HTTP {status}: {body_text}"),
207→                            retry_after_ms,
208→                        ));
209→                        return;
210→                    }
211→                    r
212→                }
213→                Err(e) => {
214→                    yield StreamEvent::Error(e.to_string());
215→                    return;
216→                }
217→            };
218→
219→            let mut byte_stream = resp.bytes_stream();
220→            let mut buf = String::new();
221→            let mut state = StreamingToolState::default();
222→
223→            while let Some(chunk) = byte_stream.next().await {
224→                let chunk = match chunk {
225→                    Ok(c) => c,
226→                    Err(e) => {
227→                        yield StreamEvent::Error(e.to_string());
228→                        return;
229→                    }
230→                };
231→                buf.push_str(&String::from_utf8_lossy(&chunk));
232→
233→                while let Some(pos) = buf.find('\n') {
234→                    let line = buf[..pos].trim().to_string();
235→                    buf = buf[pos + 1..].to_string();
236→
237→                    if line.is_empty() {
238→                        continue;
239→                    }
240→
241→                    let Some(data) = line
242→                        .strip_prefix("data: ")
243→                        .or_else(|| line.strip_prefix("data:"))
244→                    else {
245→                        continue;
246→                    };
247→
248→                    match process_openai_sse_line(data, &mut state) {
249→                        SseLineResult::Done => {
250→                            for event in finalize_stream(&mut state) {
251→                                yield event;
252→                            }
253→                            return;
254→                        }
255→                        SseLineResult::Events(events) => {
256→                            for event in events {
257→                                yield event;
258→                            }
259→                        }
260→                        SseLineResult::Skip => {}
261→                    }
262→                }
263→            }
264→
265→            // Some OpenAI-compatible providers may close the stream without
266→            // an explicit [DONE] frame or trailing newline. Process any
267→            // residual buffered line and always finalize on EOF so usage
268→            // metadata still propagates.
269→            let line = buf.trim().to_string();
270→            if !line.is_empty()
271→                && let Some(data) = line
272→                    .strip_prefix("data: ")
273→                    .or_else(|| line.strip_prefix("data:"))
274→            {
275→                match process_openai_sse_line(data, &mut state) {
276→                    SseLineResult::Done => {
277→                        for event in finalize_stream(&mut state) {
278→                            yield event;
279→                        }
280→                        return;
281→                    }
282→                    SseLineResult::Events(events) => {
283→                        for event in events {
284→                            yield event;
285→                        }
286→                    }
287→                    SseLineResult::Skip => {}
288→                }
289→            }
290→
291→            for event in finalize_stream(&mut state) {
292→                yield event;
293→            }
294→        })
295→    }
296→}
