 47→/// Streaming variant of the agent loop.
 48→///
 49→/// Unlike `run_agent_loop_with_context`, this function uses streaming to send
 50→/// text deltas to the UI as they arrive, providing a much better UX.
 51→///
 52→/// Tool calls are accumulated from the stream and executed after the stream
 53→/// completes, then the loop continues with the next iteration.
 54→pub async fn run_agent_loop_streaming(
 55→    provider: Arc<dyn LlmProvider>,
 56→    tools: &ToolRegistry,
 57→    system_prompt: &str,
 58→    user_content: &UserContent,
 59→    on_event: Option<&OnEvent>,
 60→    history: Option<Vec<ChatMessage>>,
 61→    tool_context: Option<serde_json::Value>,
 62→    hook_registry: Option<Arc<HookRegistry>>,
 63→    sender_name: Option<String>,
 64→) -> Result<AgentRunResult, AgentRunError> {
 65→    let native_tools = provider.supports_tools();
 66→    let config = moltis_config::discover_and_load();
 67→    let max_tool_result_bytes = config.tools.max_tool_result_bytes;
 68→    let max_auto_continues = config.tools.agent_max_auto_continues;
 69→    let auto_continue_min_tool_calls = config.tools.agent_auto_continue_min_tool_calls;
 70→    let base_max_iterations = resolve_agent_max_iterations(config.tools.agent_max_iterations);
 71→    // Lazy mode needs extra iterations for tool_search discovery round-trips.
 72→    let max_iterations = if config.tools.registry_mode == moltis_config::ToolRegistryMode::Lazy {
 73→        base_max_iterations * 3
 74→    } else {
 75→        base_max_iterations
 76→    };
 77→
 78→    let is_multimodal = matches!(user_content, UserContent::Multimodal(_));
 79→    info!(
 80→        provider = provider.name(),
 81→        model = provider.id(),
 82→        native_tools,
 83→        tools_count = tools.list_names().len(),
 84→        is_multimodal,
 85→        "starting streaming agent loop"
 86→    );
 87→
 88→    let mut messages: Vec<ChatMessage> = vec![ChatMessage::system(system_prompt)];
 89→
 90→    // Insert conversation history before the current user message.
 91→    if let Some(hist) = history {
 92→        messages.extend(hist);
 93→    }
 94→
 95→    messages.push(ChatMessage::User {
 96→        content: user_content.clone(),
 97→        name: sender_name,
 98→    });
 99→    let explicit_shell_command = explicit_shell_command_from_user_content(user_content);
100→
101→    // Extract session key once for hook payloads.
102→    let session_key_for_hooks = tool_context
103→        .as_ref()
104→        .and_then(|ctx| ctx.get("_session_key"))
105→        .and_then(|v| v.as_str())
106→        .unwrap_or("")
107→        .to_string();
108→    let channel_for_hooks =
109→        channel_binding_from_tool_context(&session_key_for_hooks, tool_context.as_ref());
110→
111→    let mut iterations = 0;
112→    let mut total_tool_calls = 0;
113→    let mut usage_accumulator = UsageAccumulator::default();
114→    let mut server_retries_remaining: u8 = 1;
115→    let mut rate_limit_retries_remaining: u8 = RATE_LIMIT_MAX_RETRIES;
116→    let mut rate_limit_backoff_ms: Option<u64> = None;
117→    let mut raw_llm_responses: Vec<serde_json::Value> = Vec::new();
118→    // Track answer text from iterations that also contained tool calls.
119→    // When the final iteration is empty (e.g. model stop after browser close),
120→    // this is used as the final response text instead of returning silent.
121→    let mut last_answer_text = String::new();
122→    let mut malformed_retry_count: u8 = 0;
123→    let mut empty_tool_name_retry_count: u8 = 0;
124→    let mut auto_continue_count: usize = 0;
125→    let mut loop_detector = ToolLoopDetector::new(
126→        config.tools.agent_loop_detector_window,
127→        config.tools.agent_loop_detector_strip_tools_on_second_fire,
128→    );
129→    let mut strip_tools_next_iter = false;
130→
131→    loop {
132→        iterations += 1;
133→        if iterations > max_iterations {
134→            warn!(
135→                "streaming agent loop exceeded max iterations ({})",
136→                max_iterations
137→            );
138→            return Err(AgentRunError::Other(anyhow::anyhow!(
139→                "agent loop exceeded max iterations ({})",
140→                max_iterations
141→            )));
142→        }
143→
144→        // Re-compute schemas each iteration so activated tools appear immediately.
145→        // When the loop detector has escalated to stage 2, pass an empty tool
146→        // list for this single turn so the model is forced to respond in text
147→        // (issue #658).
148→        let schemas_for_api = if native_tools && !strip_tools_next_iter {
149→            tools.list_schemas()
150→        } else {
151→            vec![]
152→        };
153→        if strip_tools_next_iter {
154→            strip_tools_next_iter = false;
155→            loop_detector.clear_strip_tools();
156→        }
157→
158→        super::enforce_tool_result_context_budget(
159→            &mut messages,
160→            &schemas_for_api,
161→            provider.context_window(),
162→        )?;
163→
164→        if let Some(cb) = on_event {
165→            cb(RunnerEvent::Iteration(iterations));
166→        }
167→
168→        info!(
169→            iteration = iterations,
170→            messages_count = messages.len(),
171→            "calling LLM (streaming)"
172→        );
173→        trace!(iteration = iterations, messages = ?messages, "LLM request messages");
174→
175→        // Dispatch BeforeLLMCall hook — may block the LLM call.
176→        if let Some(ref hooks) = hook_registry {
177→            let msgs_json: Vec<serde_json::Value> =
178→                messages.iter().map(|m| m.to_openai_value()).collect();
179→            let payload = HookPayload::BeforeLLMCall {
180→                session_key: session_key_for_hooks.clone(),
181→                provider: provider.name().to_string(),
182→                model: provider.id().to_string(),
183→                messages: serde_json::Value::Array(msgs_json),
184→                tool_count: schemas_for_api.len(),
185→                iteration: iterations,
186→            };
187→            match hooks.dispatch(&payload).await {
188→                Ok(HookAction::Block(reason)) => {
189→                    warn!(reason = %reason, "LLM call blocked by BeforeLLMCall hook");
190→                    return Err(AgentRunError::Other(anyhow::anyhow!(
191→                        "blocked by BeforeLLMCall hook: {reason}"
192→                    )));
193→                },
194→                Ok(HookAction::ModifyPayload(_)) => {
195→                    debug!("BeforeLLMCall ModifyPayload ignored (messages are typed)");
196→                },
197→                Ok(HookAction::Continue) => {},
198→                Err(e) => {
199→                    warn!(error = %e, "BeforeLLMCall hook dispatch failed");
200→                },
201→            }
202→        }
203→
204→        if let Some(cb) = on_event {
205→            cb(RunnerEvent::Thinking);
206→        }
207→
208→        // Use streaming API.
209→        #[cfg(feature = "metrics")]
210→        let iter_start = std::time::Instant::now();
211→        let mut stream = provider.stream_with_tools(messages.clone(), schemas_for_api.clone());
212→
213→        // Accumulate answer text, reasoning text, and tool calls from the stream.
214→        let mut accumulated_text = String::new();
215→        let mut accumulated_reasoning = String::new();
216→        let mut tool_calls: Vec<ToolCall> = Vec::new();
217→        // Map streaming index -> accumulated JSON args string.
218→        let mut tool_call_args: std::collections::HashMap<usize, String> =
219→            std::collections::HashMap::new();
220→        // Map streaming index -> position in the `tool_calls` vec.
221→        // The streaming index may not start at 0 (e.g. Copilot proxying
222→        // Anthropic uses the content-block index, so a text block at index 0
223→        // pushes the tool_use to index 1).
224→        let mut stream_idx_to_vec_pos: std::collections::HashMap<usize, usize> =
225→            std::collections::HashMap::new();
226→        let mut request_usage = Usage::default();
227→        let mut stream_error: Option<String> = None;
228→
229→        while let Some(event) = stream.next().await {
230→            match event {
231→                StreamEvent::Delta(text) => {
232→                    accumulated_text.push_str(&text);
233→                    if let Some(cb) = on_event {
234→                        cb(RunnerEvent::TextDelta(text));
235→                    }
236→                },
237→                StreamEvent::ProviderRaw(raw) => {
238→                    push_capped_provider_raw_event(&mut raw_llm_responses, raw);
239→                },
240→                StreamEvent::ReasoningDelta(text) => {
241→                    accumulated_reasoning.push_str(&text);
242→                    if let Some(cb) = on_event {
243→                        cb(RunnerEvent::ThinkingText(accumulated_reasoning.clone()));
244→                    }
245→                },
246→                StreamEvent::ToolCallStart { id, name, index } => {
247→                    let vec_pos = tool_calls.len();
248→                    debug!(tool = %name, id = %id, stream_index = index, vec_pos, "tool call started in stream");
249→                    tool_calls.push(ToolCall {
250→                        id,
251→                        name,
252→                        arguments: serde_json::json!({}),
253→                    });
254→                    stream_idx_to_vec_pos.insert(index, vec_pos);
255→                    tool_call_args.insert(index, String::new());
256→                },
257→                StreamEvent::ToolCallArgumentsDelta { index, delta } => {
258→                    if let Some(args) = tool_call_args.get_mut(&index) {
259→                        args.push_str(&delta);
260→                    }
261→                },
262→                StreamEvent::ToolCallComplete { index } => {
263→                    // Arguments are finalized after stream completes.
264→                    // Just log for now - we'll parse accumulated args later.
265→                    debug!(index, "tool call arguments complete");
266→                },
267→                StreamEvent::Done(usage) => {
268→                    request_usage = usage.clone();
269→                    debug!(
270→                        input_tokens = request_usage.input_tokens,
271→                        output_tokens = request_usage.output_tokens,
272→                        cache_read_tokens = request_usage.cache_read_tokens,
273→                        cache_write_tokens = request_usage.cache_write_tokens,
274→                        "stream done"
275→                    );
276→
277→                    #[cfg(feature = "metrics")]
278→                    {
279→                        let provider_name = provider.name().to_string();
280→                        let model_id = provider.id().to_string();
281→                        let duration = iter_start.elapsed().as_secs_f64();
282→                        counter!(
283→                            llm_metrics::COMPLETIONS_TOTAL,
284→                            labels::PROVIDER => provider_name.clone(),
285→                            labels::MODEL => model_id.clone()
286→                        )
287→                        .increment(1);
288→                        counter!(
289→                            llm_metrics::INPUT_TOKENS_TOTAL,
290→                            labels::PROVIDER => provider_name.clone(),
291→                            labels::MODEL => model_id.clone()
292→                        )
293→                        .increment(u64::from(usage.input_tokens));
294→                        counter!(
295→                            llm_metrics::OUTPUT_TOKENS_TOTAL,
296→                            labels::PROVIDER => provider_name.clone(),
297→                            labels::MODEL => model_id.clone()
298→                        )
299→                        .increment(u64::from(usage.output_tokens));
300→                        counter!(
301→                            llm_metrics::CACHE_READ_TOKENS_TOTAL,
302→                            labels::PROVIDER => provider_name.clone(),
303→                            labels::MODEL => model_id.clone()
304→                        )
305→                        .increment(u64::from(usage.cache_read_tokens));
306→                        counter!(
307→                            llm_metrics::CACHE_WRITE_TOKENS_TOTAL,
308→                            labels::PROVIDER => provider_name.clone(),
309→                            labels::MODEL => model_id.clone()
310→                        )
311→                        .increment(u64::from(usage.cache_write_tokens));
312→                        histogram!(
313→                            llm_metrics::COMPLETION_DURATION_SECONDS,
314→                            labels::PROVIDER => provider_name,
315→                            labels::MODEL => model_id
316→                        )
317→                        .record(duration);
318→                    }
319→                },
320→                StreamEvent::Error(msg) => {
321→                    stream_error = Some(msg);
322→                    break;
323→                },
324→            }
325→        }
326→
327→        if let Some(cb) = on_event {
328→            cb(RunnerEvent::ThinkingDone);
329→        }
330→
331→        // Handle stream errors — retry on transient failures/rate limits.
332→        if let Some(err) = stream_error {
333→            if is_context_window_error(&err) {
334→                return Err(AgentRunError::ContextWindowExceeded(err));
335→            }
336→            if let Some(delay_ms) = next_retry_delay_ms(
337→                &err,
338→                &mut server_retries_remaining,
339→                &mut rate_limit_retries_remaining,
340→                &mut rate_limit_backoff_ms,
341→            ) {
342→                // Don't count the failed attempt as an iteration.
343→                iterations -= 1;
344→                warn!(
345→                    error = %err,
346→                    delay_ms,
347→                    server_retries_remaining,
348→                    rate_limit_retries_remaining,
349→                    "transient LLM error, retrying after delay"
350→                );
351→                if let Some(cb) = on_event {
352→                    cb(RunnerEvent::RetryingAfterError {
353→                        error: err,
354→                        delay_ms,
355→                    });
356→                }
357→                tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;
358→                continue;
359→            }
360→            return Err(AgentRunError::Other(anyhow::anyhow!(err)));
361→        }
362→
363→        usage_accumulator.record_request(request_usage.clone());
364→
365→        // Finalize tool call arguments from accumulated strings.
366→        // Use stream_idx_to_vec_pos to map streaming indices (which may not
367→        // start at 0) to the actual position in the tool_calls vec.
368→        for (stream_idx, args_str) in &tool_call_args {
369→            // Emit raw accumulated string at debug level so future variants of
370→            // "default to {} because no deltas arrived" can be diagnosed
371→            // without a repro (issue #658).
372→            debug!(
373→                stream_idx,
374→                args_str = %args_str,
375→                "finalizing tool call args"
376→            );
377→            if let Some(&vec_pos) = stream_idx_to_vec_pos.get(stream_idx)
378→                && vec_pos < tool_calls.len()
379→                && !args_str.is_empty()
380→                && let Ok(args) = serde_json::from_str::<serde_json::Value>(args_str)
381→            {
382→                tool_calls[vec_pos].arguments = args;
383→            }
384→        }
385→
386→        info!(
387→            iteration = iterations,
388→            has_text = !accumulated_text.is_empty(),
389→            tool_calls_count = tool_calls.len(),
390→            input_tokens = request_usage.input_tokens,
391→            output_tokens = request_usage.output_tokens,
392→            cache_read_tokens = request_usage.cache_read_tokens,
393→            cache_write_tokens = request_usage.cache_write_tokens,
394→            "streaming LLM response complete"
395→        );
396→
397→        // Fallback: parse tool calls from model text if the provider returned
398→        // no structured tool calls (some providers/models emit text-based calls).
399→        if tool_calls.is_empty() && !accumulated_text.is_empty() {
400→            let (parsed, remaining) = parse_tool_calls_from_text(&accumulated_text);
401→            if !parsed.is_empty() {
402→                info!(
403→                    native_tools,
404→                    count = parsed.len(),
405→                    first_tool = %parsed[0].name,
406→                    "parsed tool call(s) from text fallback"
407→                );
408→                accumulated_text = remaining.unwrap_or_default();
409→                tool_calls = parsed;
410→            }
411→        }
412→
413→        // One-shot retry for malformed tool calls in streaming mode.
414→        if tool_calls.is_empty()
415→            && looks_like_failed_tool_call(&Some(accumulated_text.clone()))
416→            && malformed_retry_count == 0
417→        {
418→            malformed_retry_count += 1;
419→            info!("detected malformed tool call in stream, requesting retry");
420→            messages.push(ChatMessage::assistant(&accumulated_text));
421→            messages.push(ChatMessage::user(MALFORMED_TOOL_RETRY_PROMPT));
422→            continue;
423→        }
424→
425→        // Fallback: recover tool calls from XML blocks (<function_call>, <tool_call>).
426→        if !native_tools && tool_calls.is_empty() && !accumulated_text.is_empty() {
427→            let (cleaned, recovered) = recover_tool_calls_from_content(&accumulated_text);
428→            if !recovered.is_empty() {
429→                info!(
430→                    count = recovered.len(),
431→                    "recovered tool calls from XML blocks in streamed text"
432→                );
433→                accumulated_text = cleaned;
434→                tool_calls = recovered;
435→            }
436→        }
437→
438→        // Final fallback: if the user turn is an explicit `/sh ...` command and
439→        // the model returned plain text, force one exec tool call so this path
440→        // is deterministic in the UI.
441→        if tool_calls.is_empty()
442→            && iterations == 1
443→            && total_tool_calls == 0
444→            && let Some(command) = explicit_shell_command.as_ref()
445→            && tools.get("exec").is_some()
446→        {
447→            info!(command = %command, "forcing exec tool call from explicit /sh command");
448→            // Preserve streamed reasoning/planning text on the assistant tool
449→            // message so providers that validate thinking history accept the
450→            // next iteration.
451→            tool_calls = vec![ToolCall {
452→                id: new_synthetic_tool_call_id("forced"),
453→                name: "exec".to_string(),
454→                arguments: serde_json::json!({ "command": command }),
455→            }];
456→        }
457→
458→        if let Some(tc) = find_empty_tool_name_call(&tool_calls) {
459→            if has_named_tool_call(&tool_calls) {
460→                warn!(
461→                    tool_call_id = %tc.id,
462→                    "streamed tool call batch contains both empty and valid tool names; preserving valid sibling tool calls and falling back to normal tool error handling"
463→                );
464→            } else if empty_tool_name_retry_count == 0 {
465→                empty_tool_name_retry_count += 1;
466→                info!(tool_call_id = %tc.id, "detected structured tool call with empty name in stream, requesting retry");
467→                let retry_text = streaming_tool_call_message_content(
468→                    &mut last_answer_text,
469→                    &accumulated_text,
470→                    &accumulated_reasoning,
471→                );
472→                messages.push(ChatMessage::assistant(retry_text.unwrap_or_default()));
473→                messages.push(ChatMessage::user(empty_tool_name_retry_prompt(tc)));
474→                continue;
475→            }
476→            warn!(
477→                tool_call_id = %tc.id,
478→                "structured tool call in stream still has empty name after retry; falling back to normal tool error handling"
479→            );
480→        }
481→
482→        dispatch_after_llm_call_hook(
483→            hook_registry.as_ref(),
484→            &session_key_for_hooks,
485→            provider.name(),
486→            provider.id(),
487→            (!accumulated_text.is_empty()).then(|| accumulated_text.clone()),
488→            &tool_calls,
489→            &request_usage,
490→            iterations,
491→        )
492→        .await?;
493→
494→        // If no tool calls, auto-continue or return the text response.
495→        if tool_calls.is_empty() {
496→            // Auto-continue: if the model made tool calls earlier in this run
497→            // and we haven't exhausted nudges, ask it to keep going. Suppress
498→            // the nudge when the model already produced a substantive final
499→            // answer — nudging in that case risks losing the answer (GH #628).
500→            if !is_substantive_answer_text(&accumulated_text)
501→                && total_tool_calls > 0
502→                && total_tool_calls >= auto_continue_min_tool_calls
503→                && auto_continue_count < max_auto_continues
504→            {
505→                auto_continue_count += 1;
506→                info!(
507→                    iterations,
508→                    auto_continue_count, "model stopped without tool calls, auto-continuing"
509→                );
510→                if let Some(cb) = on_event {
511→                    cb(RunnerEvent::AutoContinue {
512→                        iteration: iterations,
513→                        max_iterations,
514→                    });
515→                }
516→                if !accumulated_text.is_empty() {
517→                    messages.push(ChatMessage::assistant(&accumulated_text));
518→                }
519→                messages.push(ChatMessage::user(AUTO_CONTINUE_NUDGE));
520→                continue;
521→            }
522→
523→            // When the final iteration produced no text but a previous iteration
524→            // streamed answer text alongside tool calls, use that as the response.
525→            let final_text = if accumulated_text.is_empty() && !last_answer_text.is_empty() {
526→                std::mem::take(&mut last_answer_text)
527→            } else {
528→                accumulated_text
529→            };
530→            info!(
531→                iterations,
532→                tool_calls = total_tool_calls,
533→                "streaming agent loop complete — returning text"
534→            );
535→            return Ok(finish_agent_run(
536→                final_text,
537→                iterations,
538→                total_tool_calls,
539→                &usage_accumulator,
540→                raw_llm_responses,
541→            ));
542→        }
543→
544→        // Append assistant message with tool calls.
545→        //
546→        // When the model emits explicit reasoning (extended thinking), use
547→        // that as the planning text and emit it as ThinkingText for the UI.
548→        // When there is only regular text alongside tool calls (no separate
549→        // reasoning), preserve it on the message for history but do NOT emit
550→        // it as ThinkingText — it was already streamed as TextDelta and is
551→        // likely the actual answer (e.g. a search result table produced
552→        // before a `browser close` cleanup call).
553→        let (text_for_msg, is_actual_reasoning) = if !accumulated_reasoning.is_empty() {
554→            (Some(accumulated_reasoning), true)
555→        } else if !accumulated_text.is_empty() {
556→            last_answer_text.clone_from(&accumulated_text);
557→            (Some(accumulated_text), false)
558→        } else {
559→            (None, false)
560→        };
561→        if let Some(ref text) = text_for_msg
562→            && is_actual_reasoning
563→            && let Some(cb) = on_event
564→        {
565→            cb(RunnerEvent::ThinkingText(text.clone()));
566→        }
567→        messages.push(ChatMessage::assistant_with_tools(
568→            text_for_msg,
569→            tool_calls.clone(),
570→        ));
571→
572→        // Execute tool calls concurrently.
573→        total_tool_calls += tool_calls.len();
574→
575→        // Build futures for all tool calls (executed concurrently).
576→        //
577→        // Pre-dispatch schema validation runs synchronously against each
578→        // tool's declared `parameters_schema`. Calls that fail validation
579→        // are short-circuited to a directive error response without invoking
580→        // `execute`, and the UI receives `ToolCallRejected` instead of the
581→        // misleading "executing" status (issue #658).
582→        let tool_futures: Vec<_> = tool_calls
583→            .iter()
584→            .map(|tc| {
585→                let sanitized = sanitize_tool_name(&tc.name);
586→                if *sanitized != tc.name {
587→                    debug!(original = %tc.name, sanitized = %sanitized, "sanitized mangled tool name");
588→                }
589→                let (tool, resolved_name) = resolve_tool_lookup(tools, sanitized.as_ref());
590→                if resolved_name.as_ref() != sanitized.as_ref() {
591→                    debug!(original = %sanitized, resolved = %resolved_name, "resolved legacy tool alias");
592→                }
593→                let mut args = tc.arguments.clone();
594→
595→                let hook_registry = hook_registry.clone();
596→                let session_key = session_key_for_hooks.clone();
597→                let channel_for_hooks = channel_for_hooks.clone();
598→                let tc_name = resolved_name.to_string();
599→
600→                if let Some(ref ctx) = tool_context
601→                    && let (Some(args_obj), Some(ctx_obj)) = (args.as_object_mut(), ctx.as_object())
602→                {
603→                    for (k, v) in ctx_obj {
604→                        args_obj.insert(k.clone(), v.clone());
605→                    }
606→                }
607→
608→                // Pre-dispatch validation against the tool's schema.
609→                let validation_error: Option<String> = if let Some(ref t) = tool {
610→                    let schema = t.parameters_schema();
611→                    match validate_tool_args(&schema, &args) {
612→                        Ok(()) => None,
613→                        Err(e) => {
614→                            warn!(
615→                                tool = %tc_name,
616→                                summary = %e.short_summary(),
617→                                "tool call rejected by pre-dispatch schema validation"
618→                            );
619→                            Some(e.to_llm_error_message(&tc_name))
620→                        },
621→                    }
622→                } else {
623→                    None
624→                };
625→
626→                if validation_error.is_none() {
627→                    if let Some(cb) = on_event {
628→                        cb(RunnerEvent::ToolCallStart {
629→                            id: tc.id.clone(),
630→                            name: tc.name.clone(),
631→                            arguments: args.clone(),
632→                        });
633→                    }
634→                    info!(tool = %tc_name, id = %tc.id, args = %args, "executing tool");
635→                }
636→
637→                async move {
638→                    if let Some(err_msg) = validation_error {
639→                        return (
640→                            false,
641→                            serde_json::json!({ "error": err_msg.clone() }),
642→                            Some(err_msg),
643→                            true,
644→                        );
645→                    }
646→                    // Run BeforeToolCall hook.
647→                    if let Some(ref hooks) = hook_registry {
648→                        let payload = HookPayload::BeforeToolCall {
649→                            session_key: session_key.clone(),
650→                            tool_name: tc_name.clone(),
651→                            arguments: args.clone(),
652→                            channel: channel_for_hooks.clone(),
653→                        };
654→                        match hooks.dispatch(&payload).await {
655→                            Ok(HookAction::Block(reason)) => {
656→                                warn!(tool = %tc_name, reason = %reason, "tool call blocked by hook");
657→                                let err_str = format!("blocked by hook: {reason}");
658→                                return (
659→                                    false,
660→                                    serde_json::json!({ "error": err_str }),
661→                                    Some(err_str),
662→                                    false,
663→                                );
664→                            }
665→                            Ok(HookAction::ModifyPayload(v)) => {
666→                                args = v;
667→                            }
668→                            Ok(HookAction::Continue) => {}
669→                            Err(e) => {
670→                                warn!(tool = %tc_name, error = %e, "BeforeToolCall hook dispatch failed");
671→                            }
672→                        }
673→                    }
674→
675→                    if let Some(tool) = tool {
676→                        match tool.execute(args).await {
677→                            Ok(val) => {
678→                                // Check if the result indicates a logical failure
679→                                // (e.g., BrowserResponse with success: false)
680→                                let has_error = val.get("error").is_some()
681→                                    || val.get("success") == Some(&serde_json::json!(false));
682→                                let error_msg = if has_error {
683→                                    val.get("error")
684→                                        .and_then(|e| e.as_str())
685→                                        .map(String::from)
686→                                } else {
687→                                    None
688→                                };
689→
690→                                if let Some(ref hooks) = hook_registry {
691→                                    let payload = HookPayload::AfterToolCall {
692→                                        session_key: session_key.clone(),
693→                                        tool_name: tc_name.clone(),
694→                                        success: !has_error,
695→                                        result: Some(val.clone()),
696→                                        channel: channel_for_hooks.clone(),
697→                                    };
698→                                    if let Err(e) = hooks.dispatch(&payload).await {
699→                                        warn!(tool = %tc_name, error = %e, "AfterToolCall hook dispatch failed");
700→                                    }
701→                                }
702→
703→                                if has_error {
704→                                    (false, serde_json::json!({ "result": val }), error_msg, false)
705→                                } else {
706→                                    (true, serde_json::json!({ "result": val }), None, false)
707→                                }
708→                            }
709→                            Err(e) => {
710→                                let err_str = e.to_string();
711→                                if let Some(ref hooks) = hook_registry {
712→                                    let payload = HookPayload::AfterToolCall {
713→                                        session_key: session_key.clone(),
714→                                        tool_name: tc_name.clone(),
715→                                        success: false,
716→                                        result: None,
717→                                        channel: channel_for_hooks.clone(),
718→                                    };
719→                                    if let Err(e) = hooks.dispatch(&payload).await {
720→                                        warn!(tool = %tc_name, error = %e, "AfterToolCall hook dispatch failed");
721→                                    }
722→                                }
723→                                (
724→                                    false,
725→                                    serde_json::json!({ "error": err_str }),
726→                                    Some(err_str),
727→                                    false,
728→                                )
729→                            }
730→                        }
731→                    } else {
732→                        let err_str = format!("unknown tool: {tc_name}");
733→                        (
734→                            false,
735→                            serde_json::json!({ "error": err_str }),
736→                            Some(err_str),
737→                            false,
738→                        )
739→                    }
740→                }
741→            })
742→            .collect();
743→
744→        // Execute all tools concurrently and collect results in order.
745→        let results = futures::future::join_all(tool_futures).await;
746→
747→        // Process results in original order: emit events, append messages.
748→        // Intervention is derived from the detector's post-batch state
749→        // via `consume_pending_action()` below — see the non-streaming
750→        // path for the rationale (issue #658).
751→        for (tc, (success, mut result, error, rejected)) in tool_calls.iter().zip(results) {
752→            if success {
753→                info!(tool = %tc.name, id = %tc.id, "tool execution succeeded");
754→                trace!(tool = %tc.name, result = %result, "tool result");
755→            } else if rejected {
756→                warn!(
757→                    tool = %tc.name,
758→                    id = %tc.id,
759→                    "tool call rejected before execution by pre-dispatch validation"
760→                );
761→            } else {
762→                warn!(tool = %tc.name, id = %tc.id, error = %error.as_deref().unwrap_or(""), "tool execution failed");
763→            }
764→
765→            // Record outcome in the loop detector (issue #658).
766→            if loop_detector.is_enabled() {
767→                let fp = if success {
768→                    ToolCallFingerprint::success(&tc.name, &tc.arguments)
769→                } else {
770→                    ToolCallFingerprint::failure(&tc.name, &tc.arguments, error.as_deref())
771→                };
772→                let _ = loop_detector.record(fp);
773→            }
774→
775→            if let Some(cb) = on_event {
776→                if rejected {
777→                    cb(RunnerEvent::ToolCallRejected {
778→                        id: tc.id.clone(),
779→                        name: tc.name.clone(),
780→                        arguments: tc.arguments.clone(),
781→                        error: error.clone().unwrap_or_default(),
782→                    });
783→                } else {
784→                    cb(RunnerEvent::ToolCallEnd {
785→                        id: tc.id.clone(),
786→                        name: tc.name.clone(),
787→                        success,
788→                        error,
789→                        result: if success {
790→                            result.get("result").cloned()
791→                        } else {
792→                            None
793→                        },
794→                    });
795→                }
796→            }
797→
798→            // Dispatch ToolResultPersist hook — the last opportunity for a handler
799→            // to sanitize, redact, or block attacker-controlled tool output before
800→            // it enters the messages array and is reasoned on by the next LLM
801→            // iteration. Block substitutes an error marker instead of aborting the
802→            // run, so a single hostile tool result cannot kill a long-running
803→            // autonomous agent.
804→            if let Some(ref hooks) = hook_registry {
805→                let payload = HookPayload::ToolResultPersist {
806→                    session_key: session_key_for_hooks.clone(),
807→                    tool_name: sanitize_tool_name(&tc.name).into_owned(),
808→                    result: result.clone(),
809→                    channel: channel_for_hooks.clone(),
810→                };
811→                match hooks.dispatch(&payload).await {
812→                    Ok(HookAction::ModifyPayload(v)) => {
813→                        debug!(tool = %tc.name, "ToolResultPersist replaced tool result");
814→                        result = v;
815→                    },
816→                    Ok(HookAction::Block(reason)) => {
817→                        warn!(tool = %tc.name, reason = %reason, "ToolResultPersist blocked result — substituting error marker");
818→                        result = serde_json::json!({
819→                            "error": format!("blocked by hook: {reason}")
820→                        });
821→                    },
822→                    Ok(HookAction::Continue) => {},
823→                    Err(e) => {
824→                        warn!(tool = %tc.name, error = %e, "ToolResultPersist hook dispatch failed");
825→                    },
826→                }
827→            }
828→
829→            // Always sanitize tool results as strings - most LLM APIs don't support
830→            // multimodal content in tool results. Images are stripped but the UI
831→            // still receives them via ToolCallEnd event.
832→            let tool_result_str = sanitize_tool_result(&result.to_string(), max_tool_result_bytes);
833→            debug!(
834→                tool = %tc.name,
835→                id = %tc.id,
836→                result_len = tool_result_str.len(),
837→                "appending tool result to messages"
838→            );
839→            trace!(tool = %tc.name, content = %tool_result_str, "tool result message content");
840→
841→            messages.push(ChatMessage::tool(&tc.id, &tool_result_str));
842→        }
843→
844→        // Apply loop-detector intervention if one fired during this batch.
845→        apply_loop_detector_intervention(
846→            &mut loop_detector,
847→            &mut messages,
848→            &mut strip_tools_next_iter,
849→            on_event,
850→        );
851→    }
852→}
