 64→/// Make a JSON Schema node nullable by adding `"null"` to its type.
 65→///
 66→/// For schemas using `"type": "string"` (or any single type), this converts to
 67→/// `"type": ["string", "null"]`.  For schemas using `anyOf`/`oneOf`, it appends
 68→/// a `{"type": "null"}` variant.  Already-nullable schemas are left unchanged.
 69→fn make_nullable(schema: &mut serde_json::Value) {
 70→    let Some(obj) = schema.as_object_mut() else {
 71→        return;
 72→    };
 73→
 74→    // If it already has a "null" type, nothing to do.
 75→    if let Some(ty) = obj.get("type") {
 76→        if ty.as_str() == Some("null") {
 77→            return;
 78→        }
 79→        if let Some(arr) = ty.as_array()
 80→            && arr.iter().any(|v| v.as_str() == Some("null"))
 81→        {
 82→            return;
 83→        }
 84→    }
 85→
 86→    // Case 1: has a `type` field — convert to array form with "null".
 87→    if let Some(ty) = obj.get("type").cloned() {
 88→        if let Some(s) = ty.as_str() {
 89→            obj.insert("type".to_string(), serde_json::json!([s, "null"]));
 90→        } else if let Some(arr) = ty.as_array() {
 91→            let mut new_arr = arr.clone();
 92→            new_arr.push(serde_json::json!("null"));
 93→            obj.insert("type".to_string(), serde_json::Value::Array(new_arr));
 94→        }
 95→        return;
 96→    }
 97→
 98→    // Case 2: uses anyOf/oneOf — append a null variant.
 99→    for key in ["anyOf", "oneOf"] {
100→        if let Some(variants) = obj.get_mut(key).and_then(|v| v.as_array_mut()) {
101→            let has_null = variants
102→                .iter()
103→                .any(|v| v.get("type").and_then(|t| t.as_str()) == Some("null"));
104→            if !has_null {
105→                variants.push(serde_json::json!({"type": "null"}));
106→            }
107→            return;
108→        }
109→    }
110→}
