112→/// Check whether a schema's `type` field designates an object.
113→///
114→/// Matches both `"type": "object"` and `"type": ["object", ...]`.
115→/// Downstream providers like Gemini (via OpenRouter) cannot represent type
116→/// arrays, and OpenAI's strict mode requires `type` to be a single string.
117→fn type_is_object(obj: &serde_json::Map<String, serde_json::Value>) -> bool {
118→    let Some(ty) = obj.get("type") else {
119→        return false;
120→    };
121→    match ty {
122→        serde_json::Value::String(s) => s == "object",
123→        serde_json::Value::Array(arr) => arr.iter().any(|v| v.as_str() == Some("object")),
124→        _ => false,
125→    }
126→}
