128→/// Recursively patch schema for OpenAI strict mode compliance.
129→///
130→/// OpenAI's strict mode requires:
131→/// 1. `additionalProperties: false` on every object in the schema tree
132→/// 2. All properties must be listed in the `required` array
133→///
134→/// Properties not in the original `required` array are made nullable so the
135→/// model can send `null` for unused optional fields instead of fabricating
136→/// placeholder values.
137→///
138→/// Schemas with `type: ["object", "string", ...]` (union types) are collapsed
139→/// to `type: "object"` because:
140→/// - OpenAI strict mode requires `type` to be a single string
141→/// - Gemini cannot represent type arrays at all
142→/// - When `properties` is present, the object form is the intended shape for
143→///   tool calling (bare strings/integers are convenience shorthand for non-tool
144→///   contexts)
145→///
146→/// This function recursively patches nested objects in `properties`, array
147→/// `items`, `anyOf`/`oneOf`/`allOf` variants, etc.
148→pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
149→    let Some(obj) = schema.as_object_mut() else {
150→        return;
151→    };
152→
153→    // Collect originally-optional property names so we can make them nullable
154→    // AFTER recursion (otherwise changing "type":"object" to ["object","null"]
155→    // would prevent the recursive pass from recognising nested objects).
156→    let mut optional_props: Vec<String> = Vec::new();
157→
158→    // If this is an object type, apply strict mode requirements.
159→    // Also handles union types like ["object", "string"] by collapsing to "object".
160→    if type_is_object(obj) {
161→        // Collapse type arrays (e.g. ["object", "string"]) to "object".
162→        // OpenAI strict mode and Gemini both require a single string type.
163→        if obj.get("type").and_then(|t| t.as_array()).is_some() {
164→            obj.insert("type".to_string(), serde_json::json!("object"));
165→        }
166→        // Add additionalProperties: false
167→        obj.insert("additionalProperties".to_string(), serde_json::json!(false));
168→
169→        // Ensure all properties are in required array.
170→        if let Some(props) = obj.get("properties").and_then(|p| p.as_object()).cloned() {
171→            let originally_required: HashSet<String> = obj
172→                .get("required")
173→                .and_then(|r| r.as_array())
174→                .map(|arr| {
175→                    arr.iter()
176→                        .filter_map(|v| v.as_str().map(String::from))
177→                        .collect()
178→                })
179→                .unwrap_or_default();
180→
181→            let all_prop_names: Vec<serde_json::Value> =
182→                props.keys().map(|k| serde_json::json!(k)).collect();
183→            obj.insert("required".to_string(), serde_json::json!(all_prop_names));
184→
185→            // Remember which properties need to be made nullable (deferred).
186→            for key in props.keys() {
187→                if !originally_required.contains(key) {
188→                    optional_props.push(key.clone());
189→                }
190→            }
191→        } else {
192→            // Object without properties - add empty properties and required
193→            obj.insert("properties".to_string(), serde_json::json!({}));
194→            obj.insert("required".to_string(), serde_json::json!([]));
195→        }
196→    }
197→
198→    // Recurse into properties
199→    if let Some(props) = obj.get_mut("properties").and_then(|p| p.as_object_mut()) {
