617→pub struct StreamingToolState {
618→    /// Map from index -> (id, name, arguments_buffer)
619→    pub tool_calls: HashMap<usize, (String, String, String)>,
620→    pub input_tokens: u32,
621→    pub output_tokens: u32,
622→    pub cache_read_tokens: u32,
623→    pub cache_write_tokens: u32,
624→    /// Whether we are currently inside a `<think>` block in streamed content.
625→    in_think_block: bool,
626→    /// Whether we are still stripping leading whitespace at the start of a
627→    /// think block. Set to `true` when entering `<think>`, cleared once
628→    /// non-whitespace reasoning content is emitted.
629→    think_strip_leading_ws: bool,
630→    /// Whether we are still stripping leading whitespace from visible content
631→    /// after exiting a `</think>` block. Models often emit `\n\n` between
632→    /// `</think>` and the actual answer.
633→    visible_strip_leading_ws: bool,
634→    /// Buffer for detecting `<think>` / `</think>` tags that may be split
635→    /// across SSE chunk boundaries.
