639→/// Result of processing a single SSE line.
640→#[derive(Debug)]
641→pub enum SseLineResult {
642→    /// No actionable event (empty line, non-data prefix)
643→    Skip,
644→    /// Stream is done
645→    Done,
646→    /// Events to yield
647→    Events(Vec<StreamEvent>),
648→}
