650→/// Emit a `ReasoningDelta`, stripping leading whitespace at the start of a
651→/// think block so the UI doesn't show a blank prefix.
652→fn emit_reasoning(text: String, strip_leading_ws: &mut bool, events: &mut Vec<StreamEvent>) {
653→    if text.is_empty() {
654→        return;
655→    }
656→    let emitted = if *strip_leading_ws {
657→        let trimmed = text.trim_start();
658→        if trimmed.is_empty() {
659→            // Entire chunk was whitespace — keep stripping
660→            return;
661→        }
662→        *strip_leading_ws = false;
663→        trimmed.to_string()
664→    } else {
665→        text
666→    };
667→    events.push(StreamEvent::ReasoningDelta(emitted));
668→}
669→
670→/// Emit a visible `Delta`, stripping leading whitespace after a `</think>`
671→/// block so the UI doesn't show blank lines before the answer.
672→fn emit_visible(text: String, strip_leading_ws: &mut bool, events: &mut Vec<StreamEvent>) {
673→    if text.is_empty() {
674→        return;
675→    }
676→    let emitted = if *strip_leading_ws {
677→        let trimmed = text.trim_start();
678→        if trimmed.is_empty() {
679→            // Entire chunk was whitespace — keep stripping
680→            return;
681→        }
682→        *strip_leading_ws = false;
683→        trimmed.to_string()
684→    } else {
685→        text
686→    };
687→    events.push(StreamEvent::Delta(emitted));
688→}
689→
690→/// Process streamed content through the `<think>` tag state machine.
691→///
692→/// Content arriving inside `<think>...</think>` is emitted as
693→/// `ReasoningDelta`; content outside is emitted as `Delta`.
694→/// Tags may be split across SSE chunks — `tag_buffer` accumulates
695→/// partial tag fragments until they can be resolved.
696→/// Leading whitespace at the start of each think block is stripped.
697→fn process_content_think_tags(
698→    content: &str,
699→    state: &mut StreamingToolState,
700→    events: &mut Vec<StreamEvent>,
701→) {
702→    state.tag_buffer.push_str(content);
703→
704→    loop {
705→        if state.in_think_block {
706→            // Look for </think> to exit think mode
707→            match state.tag_buffer.find("</think>") {
708→                Some(pos) => {
709→                    let thinking = state.tag_buffer[..pos].to_string();
710→                    emit_reasoning(thinking, &mut state.think_strip_leading_ws, events);
711→                    state.in_think_block = false;
712→                    state.visible_strip_leading_ws = true;
713→                    let rest = state.tag_buffer[pos + "</think>".len()..].to_string();
714→                    state.tag_buffer = rest;
715→                    // Continue loop to process remaining content
716→                },
717→                None => {
718→                    // Check if buffer ends with a prefix of "</think>"
719→                    // to avoid emitting partial tag as reasoning text.
720→                    let suffix_match = longest_tag_suffix(&state.tag_buffer, "</think>");
721→                    if suffix_match > 0 {
722→                        let safe = state.tag_buffer.len() - suffix_match;
723→                        let emit = state.tag_buffer[..safe].to_string();
724→                        emit_reasoning(emit, &mut state.think_strip_leading_ws, events);
725→                        let kept = state.tag_buffer[safe..].to_string();
726→                        state.tag_buffer = kept;
727→                    } else {
728→                        // No partial tag — emit everything as reasoning
729→                        let buf = std::mem::take(&mut state.tag_buffer);
730→                        emit_reasoning(buf, &mut state.think_strip_leading_ws, events);
731→                    }
732→                    break;
733→                },
734→            }
735→        } else {
736→            // Look for <think> to enter think mode
737→            match state.tag_buffer.find("<think>") {
738→                Some(pos) => {
739→                    let visible = state.tag_buffer[..pos].to_string();
740→                    emit_visible(visible, &mut state.visible_strip_leading_ws, events);
741→                    state.in_think_block = true;
742→                    state.think_strip_leading_ws = true;
743→                    let rest = state.tag_buffer[pos + "<think>".len()..].to_string();
744→                    state.tag_buffer = rest;
745→                    // Continue loop to process remaining content
746→                },
747→                None => {
748→                    // Check if buffer ends with a prefix of "<think>"
749→                    let suffix_match = longest_tag_suffix(&state.tag_buffer, "<think>");
750→                    if suffix_match > 0 {
751→                        let safe = state.tag_buffer.len() - suffix_match;
752→                        let emit = state.tag_buffer[..safe].to_string();
753→                        emit_visible(emit, &mut state.visible_strip_leading_ws, events);
754→                        let kept = state.tag_buffer[safe..].to_string();
755→                        state.tag_buffer = kept;
756→                    } else {
757→                        // No partial tag — emit everything as visible
758→                        let buf = std::mem::take(&mut state.tag_buffer);
759→                        emit_visible(buf, &mut state.visible_strip_leading_ws, events);
760→                    }
761→                    break;
762→                },
763→            }
764→        }
765→    }
766→}

796→pub fn process_openai_sse_line(data: &str, state: &mut StreamingToolState) -> SseLineResult {
797→    if data == "[DONE]" {
798→        return SseLineResult::Done;
799→    }
800→
801→    let Ok(evt) = serde_json::from_str::<serde_json::Value>(data) else {
802→        return SseLineResult::Skip;
803→    };
804→
805→    let mut events = vec![StreamEvent::ProviderRaw(evt.clone())];
806→
807→    if let Some(usage) = parse_openai_compat_usage_from_payload(&evt) {
808→        state.input_tokens = usage.input_tokens;
809→        state.output_tokens = usage.output_tokens;
810→        state.cache_read_tokens = usage.cache_read_tokens;
811→        state.cache_write_tokens = usage.cache_write_tokens;
812→    }
813→
814→    let delta = &evt["choices"][0]["delta"];
815→
816→    // Handle user-visible text content, stripping <think> tags.
817→    if let Some(content) = delta["content"].as_str()
818→        && !content.is_empty()
819→    {
820→        process_content_think_tags(content, state, &mut events);
821→    }
822→
823→    // Some OpenAI-compatible backends stream planning text in
824→    // `reasoning_content` or `reasoning`. Surface it separately so UI can
825→    //  show it in the thinking area without polluting final assistant text.
826→    let reasoning_text = delta["reasoning_content"]
827→        .as_str()
828→        .or_else(|| delta["reasoning"].as_str());
829→    if let Some(reasoning_content) = reasoning_text
830→        && !reasoning_content.is_empty()
831→    {
832→        events.push(StreamEvent::ReasoningDelta(reasoning_content.to_string()));
833→    }
834→
835→    // Handle tool calls
836→    if let Some(tcs) = delta["tool_calls"].as_array() {
837→        for tc in tcs {
838→            let index = tc["index"].as_u64().unwrap_or(0) as usize;
839→
840→            // Check if this is a new tool call (has id and function.name)
841→            if let (Some(id), Some(name)) = (tc["id"].as_str(), tc["function"]["name"].as_str()) {
842→                state
843→                    .tool_calls
844→                    .insert(index, (id.to_string(), name.to_string(), String::new()));
845→                events.push(StreamEvent::ToolCallStart {
846→                    id: id.to_string(),
847→                    name: name.to_string(),
848→                    index,
849→                });
850→            }
851→
852→            // Handle arguments delta
853→            if let Some(args_delta) = tc["function"]["arguments"].as_str()
854→                && !args_delta.is_empty()
855→            {
856→                if let Some((_, _, args_buf)) = state.tool_calls.get_mut(&index) {
857→                    args_buf.push_str(args_delta);
858→                }
859→                events.push(StreamEvent::ToolCallArgumentsDelta {
860→                    index,
861→                    delta: args_delta.to_string(),
862→                });
863→            }
864→        }
865→    }
866→
867→    // Detect error finish reasons (e.g. "network_error", "content_filter").
868→    // Normal reasons (null, "stop", "tool_calls", "length") are not errors.
869→    if let Some(reason) = evt["choices"][0]["finish_reason"].as_str() {
870→        match reason {
871→            "stop" | "tool_calls" | "length" | "function_call" => {},
872→            error_reason => {
873→                events.push(StreamEvent::Error(format!(
874→                    "Provider stream ended with finish_reason: {error_reason}"
875→                )));
876→            },
877→        }
878→    }
879→
880→    SseLineResult::Events(events)
881→}
