919→/// Split system messages into `instructions` and convert the rest to Responses
920→/// API `input` items.
921→///
922→/// The Responses API uses a top-level `instructions` field instead of a system
923→/// message role.  This function extracts all system messages, joins them with
924→/// `\n\n`, and converts the remaining messages via [`to_responses_input`].
925→#[must_use]
926→pub fn split_responses_instructions_and_input(
927→    messages: Vec<ChatMessage>,
928→) -> (Option<String>, Vec<serde_json::Value>) {
929→    let mut instruction_parts: Vec<String> = Vec::new();
930→    let mut non_system: Vec<ChatMessage> = Vec::new();
931→
932→    for message in messages {
933→        match message {
934→            ChatMessage::System { content } => {
935→                if !content.trim().is_empty() {
936→                    instruction_parts.push(content);
937→                }
938→            },
939→            other => non_system.push(other),
940→        }
941→    }
942→
943→    let instructions = if instruction_parts.is_empty() {
944→        None
945→    } else {
946→        Some(instruction_parts.join("\n\n"))
947→    };
948→
949→    (instructions, to_responses_input(&non_system))
950→}
