952→/// Resolve the output index from a Responses API event.
953→///
954→/// The Responses API uses `output_index` for items and `index` for
955→/// sub-item fields.  WebSocket events may also use `item_index`.
956→/// Falls back to `fallback` if none of these keys are present.
957→pub fn responses_output_index(event: &serde_json::Value, fallback: usize) -> usize {
958→    event
959→        .get("output_index")
960→        .or_else(|| event.get("item_index"))
961→        .or_else(|| event.get("index"))
962→        .and_then(serde_json::Value::as_u64)
963→        .map(|i| i as usize)
964→        .unwrap_or(fallback)
965→}
