 982→/// Process a single SSE data line from a Responses API stream.
 983→///
 984→/// Returns [`SseLineResult`] indicating whether to skip, yield events, or stop.
 985→///
 986→/// Handles the event types emitted by the Responses API:
 987→/// - `response.output_text.delta` → text delta + `ProviderRaw`
 988→/// - `response.output_item.added` (type=function_call) → tool call start + `ProviderRaw`
 989→/// - `response.function_call_arguments.delta` → tool call arguments delta + `ProviderRaw`
 990→/// - `response.function_call_arguments.done` → tool call complete + `ProviderRaw`
 991→/// - `response.completed` → parse usage, done
 992→/// - `error` / `response.failed` → error + `ProviderRaw`
 993→pub fn process_responses_sse_line(data: &str, state: &mut ResponsesStreamState) -> SseLineResult {
 994→    if data == "[DONE]" {
 995→        return SseLineResult::Done;
 996→    }
 997→
 998→    let Ok(evt) = serde_json::from_str::<serde_json::Value>(data) else {
 999→        return SseLineResult::Skip;
1000→    };
1001→
1002→    // Emit ProviderRaw for every parsed event, mirroring the Chat Completions path.
1003→    let raw = StreamEvent::ProviderRaw(evt.clone());
1004→
1005→    match evt["type"].as_str().unwrap_or("") {
1006→        "response.output_text.delta" => {
1007→            if let Some(delta) = evt["delta"].as_str()
1008→                && !delta.is_empty()
1009→            {
1010→                SseLineResult::Events(vec![raw, StreamEvent::Delta(delta.to_string())])
1011→            } else {
1012→                SseLineResult::Events(vec![raw])
1013→            }
1014→        },
1015→        "response.output_item.added" => {
1016→            if evt["item"]["type"].as_str() == Some("function_call") {
1017→                let id = evt["item"]["call_id"].as_str().unwrap_or("").to_string();
1018→                let name = evt["item"]["name"].as_str().unwrap_or("").to_string();
1019→                let index = responses_output_index(&evt, state.current_tool_index);
1020→                state.current_tool_index = state.current_tool_index.max(index + 1);
1021→                state.tool_calls.insert(index, (id.clone(), name.clone()));
1022→                SseLineResult::Events(vec![raw, StreamEvent::ToolCallStart { id, name, index }])
1023→            } else {
1024→                SseLineResult::Events(vec![raw])
1025→            }
1026→        },
1027→        "response.function_call_arguments.delta" => {
1028→            if let Some(delta) = evt["delta"].as_str()
1029→                && !delta.is_empty()
1030→            {
1031→                let index =
1032→                    responses_output_index(&evt, state.current_tool_index.saturating_sub(1));
1033→                SseLineResult::Events(vec![raw, StreamEvent::ToolCallArgumentsDelta {
1034→                    index,
1035→                    delta: delta.to_string(),
1036→                }])
1037→            } else {
1038→                SseLineResult::Events(vec![raw])
1039→            }
1040→        },
1041→        "response.function_call_arguments.done" => {
1042→            let index = responses_output_index(&evt, state.current_tool_index.saturating_sub(1));
1043→            if state.completed_tool_calls.insert(index) {
1044→                SseLineResult::Events(vec![raw, StreamEvent::ToolCallComplete { index }])
1045→            } else {
1046→                SseLineResult::Events(vec![raw])
1047→            }
1048→        },
1049→        "response.completed" => {
1050→            if let Some(usage) = evt
1051→                .get("response")
1052→                .and_then(|response| response.get("usage"))
1053→            {
1054→                let parsed = parse_openai_compat_usage(usage);
1055→                state.input_tokens = parsed.input_tokens;
1056→                state.output_tokens = parsed.output_tokens;
1057→                state.cache_read_tokens = parsed.cache_read_tokens;
1058→                state.cache_write_tokens = parsed.cache_write_tokens;
1059→            }
1060→            SseLineResult::Done
1061→        },
1062→        "error" | "response.failed" => {
1063→            let msg = evt["error"]["message"]
1064→                .as_str()
1065→                .or_else(|| evt["response"]["error"]["message"].as_str())
1066→                .or_else(|| evt["message"].as_str())
1067→                .unwrap_or("unknown error");
1068→            SseLineResult::Events(vec![raw, StreamEvent::Error(msg.to_string())])
1069→        },
1070→        _ => SseLineResult::Events(vec![raw]),
1071→    }
1072→}
