1074→/// Generate the final events when a Responses API stream ends.
1075→///
1076→/// Emits `ToolCallComplete` for any pending tool calls and a final `Done` with
1077→/// accumulated usage.
1078→pub fn finalize_responses_stream(state: &mut ResponsesStreamState) -> Vec<StreamEvent> {
1079→    let mut events = Vec::new();
1080→
1081→    let mut pending: Vec<usize> = state.tool_calls.keys().copied().collect();
1082→    pending.sort_unstable();
1083→    for index in pending {
1084→        if state.completed_tool_calls.insert(index) {
1085→            events.push(StreamEvent::ToolCallComplete { index });
1086→        }
1087→    }
1088→
1089→    events.push(StreamEvent::Done(Usage {
1090→        input_tokens: state.input_tokens,
1091→        output_tokens: state.output_tokens,
1092→        cache_read_tokens: state.cache_read_tokens,
1093→        cache_write_tokens: state.cache_write_tokens,
1094→    }));
1095→
1096→    events
1097→}
