 65→/// Strip `<tag ...>content</tag>` pairs, handling optional attributes.
 66→///
 67→/// Matches opening tags with or without attributes (e.g. `<thinking>`,
 68→/// `<thinking type="deep">`), and removes everything up to and including
 69→/// the corresponding closing tag.
 70→fn strip_xml_tag(text: &str, tag: &str) -> String {
 71→    let mut result = String::with_capacity(text.len());
 72→    let mut rest = text;
 73→
 74→    let open_exact = format!("<{tag}>");
 75→    let open_with_space = format!("<{tag} ");
 76→    let close = format!("</{tag}>");
 77→
 78→    loop {
 79→        // Find the earliest opening tag variant.
 80→        let exact_pos = rest.find(&open_exact);
 81→        let space_pos = rest.find(&open_with_space);
 82→
 83→        let start = match (exact_pos, space_pos) {
 84→            (Some(a), Some(b)) => Some(a.min(b)),
 85→            (Some(a), None) => Some(a),
 86→            (None, Some(b)) => Some(b),
 87→            (None, None) => None,
 88→        };
 89→
 90→        let Some(start) = start else {
 91→            result.push_str(rest);
 92→            break;
 93→        };
 94→
 95→        // Push everything before the tag.
 96→        result.push_str(&rest[..start]);
 97→
 98→        // Find the end of the opening tag (the `>`).
 99→        let after_open = &rest[start..];
100→        let Some(gt_pos) = after_open.find('>') else {
101→            // Malformed tag — keep everything as-is.
102→            result.push_str(&rest[start..]);
103→            break;
104→        };
105→
106→        // Now look for the closing tag.
107→        let after_open_tag = &rest[start + gt_pos + 1..];
108→        if let Some(close_pos) = after_open_tag.find(&close) {
109→            // Skip past the closing tag.
110→            rest = &after_open_tag[close_pos + close.len()..];
111→        } else {
112→            // No closing tag — strip everything from open tag to end
113→            // (the tag is likely wrapping remaining content).
114→            break;
115→        }
116→    }
117→    result
118→}
