136→        let after_open = &rest[start + open.len()..];
137→        if let Some(close_pos) = after_open.find(&close) {
138→            rest = &after_open[close_pos + close.len()..];
139→        } else {
140→            // No closing tag — strip to end.
141→            break;
142→        }
143→    }
144→    result
145→}
146→
147→/// Strip standalone pipe tokens (`<|eot_id|>`, `<|im_end|>`, etc.).
148→fn strip_standalone_pipe_tokens(text: &str) -> String {
149→    let mut result = text.to_string();
150→    for token in STANDALONE_PIPE_TOKENS {
151→        // Simple replacement — these tokens are always standalone.
152→        result = result.replace(token, "");
153→    }
154→    result
155→}
156→
157→/// Strip reasoning pattern blocks: `<Thinking>...</Thinking>` and similar
158→/// capitalized variants that some models produce at the start of responses.
159→fn strip_reasoning_patterns(text: &str) -> String {
160→    let mut result = text.to_string();
161→    // Handle capitalized variants not covered by the lowercase tag list.
162→    for tag in &["Thinking", "Reflection", "Reasoning", "Analysis"] {
163→        result = strip_xml_tag(&result, tag);
164→    }
165→    result
166→}
167→
168→/// Attempt to recover structured `ToolCall` from `<function_call>` or
169→/// `<tool_call>` XML blocks embedded in the response text.
170→///
171→/// Returns the cleaned text (with recovered blocks removed) and any
172→/// recovered tool calls.
173→pub fn recover_tool_calls_from_content(text: &str) -> (String, Vec<ToolCall>) {
174→    let mut cleaned = text.to_string();
175→    let mut tool_calls = Vec::new();
176→
177→    for tag in TOOL_CALL_TAGS {
178→        let open_exact = format!("<{tag}>");
179→        let open_with_space = format!("<{tag} ");
180→        let close = format!("</{tag}>");
181→
182→        loop {
183→            let exact_pos = cleaned.find(&open_exact);
184→            let space_pos = cleaned.find(&open_with_space);
185→
186→            let start = match (exact_pos, space_pos) {
187→                (Some(a), Some(b)) => Some(a.min(b)),
188→                (Some(a), None) => Some(a),
189→                (None, Some(b)) => Some(b),
190→                (None, None) => None,
191→            };
192→
193→            let Some(start) = start else {
194→                break;
195→            };
196→
197→            let after_open = &cleaned[start..];
198→            let Some(gt_pos) = after_open.find('>') else {
199→                break;
200→            };
201→
202→            let content_start = start + gt_pos + 1;
203→            let after_content = &cleaned[content_start..];
204→
205→            let Some(close_pos) = after_content.find(&close) else {
206→                break;
207→            };
208→
209→            let xml_content = &cleaned[content_start..content_start + close_pos].trim();
210→
211→            // Try to parse the content as JSON to extract tool call info.
212→            if let Some(tc) = parse_tool_call_json(xml_content) {
213→                tool_calls.push(tc);
214→            }
215→
216→            // Remove the entire block from cleaned text.
217→            let end = content_start + close_pos + close.len();
218→            cleaned = format!("{}{}", &cleaned[..start], &cleaned[end..]);
219→        }
220→    }
221→
222→    (cleaned.trim().to_string(), tool_calls)
223→}
224→
225→/// Parse JSON content from an XML tool call block into a `ToolCall`.
226→///
227→/// Accepts formats like:
228→/// ```json
229→/// {"name": "exec", "arguments": {"command": "ls"}}
230→/// ```
231→/// or:
232→/// ```json
233→/// {"tool": "exec", "arguments": {"command": "ls"}}
234→/// ```
235→fn parse_tool_call_json(content: &str) -> Option<ToolCall> {
236→    let parsed: serde_json::Value = serde_json::from_str(content).ok()?;
237→    let name = parsed
238→        .get("name")
239→        .or_else(|| parsed.get("tool"))
