242→    let arguments = parsed
243→        .get("arguments")
244→        .or_else(|| parsed.get("parameters"))
245→        .cloned()
246→        .unwrap_or(serde_json::json!({}));
247→    let id = format!("xml-{}", uuid::Uuid::new_v4());
248→    Some(ToolCall {
249→        id,
250→        name,
251→        arguments,
252→    })
253→}
