/// Strip any remaining `<|...|>` tokens where the inner content is
/// alphanumeric/underscore. This catches model-specific control tokens
/// (e.g. `<|eom|>` from Jamba) not in the explicit known list.
fn strip_generic_pipe_tokens(text: &str) -> String {
    let mut result = String::with_capacity(text.len());
    let mut rest = text;

    loop {
        let Some(start) = rest.find("<|") else {
            result.push_str(rest);
            break;
        };

        let after_open = &rest[start + 2..];
        if let Some(close) = after_open.find("|>") {
            let token_content = &after_open[..close];
            if !token_content.is_empty()
                && token_content
                    .chars()
                    .all(|c| c.is_ascii_alphanumeric() || c == '_')
            {
                result.push_str(&rest[..start]);
                rest = &after_open[close + 2..];
            } else {
                // Not a control token pattern — keep `<|` and continue.
                result.push_str(&rest[..start + 2]);
                rest = after_open;
            }
        } else {
            result.push_str(rest);
            break;
        }
    }
    result
}

