768→/// Return the length of the longest suffix of `text` that is a prefix of `tag`.
769→///
770→/// For example, `longest_tag_suffix("abc<th", "<think>")` returns 3 because
771→/// `"<th"` is a 3-character prefix of `"<think>"`.
772→fn longest_tag_suffix(text: &str, tag: &str) -> usize {
773→    let text_bytes = text.as_bytes();
774→    let tag_bytes = tag.as_bytes();
775→    let max_check = text_bytes.len().min(tag_bytes.len());
776→    for len in (1..=max_check).rev() {
777→        if text_bytes[text_bytes.len() - len..] == tag_bytes[..len] {
778→            return len;
779→        }
780→    }
781→    0
782→}
