/// Strip `<|word|>` control tokens that some models leak into content.
///
/// Models like Jamba emit tokens such as `<|eom|>` (end-of-message) as regular
/// content deltas. This strips any `<|…|>` where the inner text is purely
/// alphanumeric/underscore, which covers all known control token formats.
pub fn strip_control_tokens(text: &str) -> String {
    let mut result = String::with_capacity(text.len());
    let mut rest = text;

    loop {
        let Some(start) = rest.find("<|") else {
            result.push_str(rest);
            break;
        };

        let after_open = &rest[start + 2..];
        if let Some(close) = after_open.find("|>") {
            let token_content = &after_open[..close];
            if !token_content.is_empty()
                && token_content
                    .chars()
                    .all(|c| c.is_ascii_alphanumeric() || c == '_')
            {
                result.push_str(&rest[..start]);
                rest = &after_open[close + 2..];
            } else {
                result.push_str(&rest[..start + 2]);
                rest = after_open;
            }
        } else {
            result.push_str(rest);
            break;
        }
    }
    result
}

