    #[test]
    fn to_openai_tools_non_strict_skips_patching() {
        let tools = vec![serde_json::json!({
            "name": "create_file",
            "description": "Create a file",
            "parameters": {
                "type": "object",
                "properties": {
                    "path": { "type": "string" },
