                                        "type": "string"
                                    }
                                ]
                            },
                            {
                                "type": "null"
                            }
                        ]
                    }
                }
            }
        })];

        let converted = to_responses_api_tools(&tools);
        let params = &converted[0]["parameters"];
        let encoded = params.to_string();

        assert_eq!(converted[0]["strict"], true);
        assert!(!encoded.contains("\"not\""));
        assert_eq!(params["type"], "object");
        assert_eq!(params["additionalProperties"], false);
        assert_eq!(params["required"], serde_json::json!(["query"]));
    }

    #[test]
    fn sanitize_schema_for_openai_compat_strips_recursive_unsupported_keywords() {
        let mut schema = serde_json::json!({
            "type": "object",
            "properties": {
                "config": {
                    "type": "object",
                    "properties": {
                        "mode": { "type": "string" }
                    },
                    "if": {
                        "required": ["mode"]
                    },
                    "then": {
                        "properties": {
                            "enabled": { "type": "boolean" }
                        }
                    },
                    "else": {
                        "properties": {
                            "enabled": { "type": "boolean" }
                        }
                    },
                    "dependentSchemas": {
                        "mode": {
                            "properties": {
                                "extra": { "type": "string" }
                            }
                        }
                    },
                    "patternProperties": {
                        "^x-": { "type": "string" }
                    },
                    "dependentRequired": {
                        "mode": ["enabled"]
                    },
                    "unevaluatedProperties": false,
                    "unevaluatedItems": false,
                    "propertyNames": {
                        "minLength": 1
                    },
                    "contains": {
                        "type": "string"
                    },
                    "minContains": 1,
                    "maxContains": 2,
                    "minProperties": 1,
                    "maxProperties": 4,
                    "const": "active",
                    "x-custom": "remove-me",
                    "items": {
                        "not": {
                            "type": "integer"
                        }
                    }
                }
            }
        });

        sanitize_schema_for_openai_compat(&mut schema);
        let encoded = schema.to_string();

        for keyword in [
            "\"if\"",
            "\"then\"",
            "\"else\"",
            "\"dependentSchemas\"",
            "\"patternProperties\"",
            "\"dependentRequired\"",
            "\"unevaluatedProperties\"",
            "\"unevaluatedItems\"",
            "\"propertyNames\"",
            "\"contains\"",
            "\"minContains\"",
            "\"maxContains\"",
            "\"minProperties\"",
            "\"maxProperties\"",
            "\"not\"",
            "\"x-custom\"",
        ] {
            assert!(!encoded.contains(keyword), "{keyword} should be removed");
        }
        assert_eq!(
            schema["properties"]["config"]["enum"],
            serde_json::json!(["active"])
        );
        assert_eq!(
            schema["properties"]["config"]["properties"]["mode"]["type"],
            "string"
        );
    }

    #[test]
    fn sanitize_schema_for_openai_compat_recurses_into_array_form_items() {
        let mut schema = serde_json::json!({
            "type": "object",
            "properties": {
                "tuple": {
                    "type": "array",
                    "items": [
                        {
                            "type": "string",
                            "not": { "const": "" }
                        },
                        {
                            "type": "object",
                            "patternProperties": {
                                "^x-": { "type": "string" }
                            }
                        }
                    ]
                }
            }
        });

        sanitize_schema_for_openai_compat(&mut schema);

        let Some(tuple_items) = schema["properties"]["tuple"]["items"].as_array() else {
            panic!("tuple items should remain an array");
        };
        assert!(tuple_items[0].get("not").is_none());
        assert!(tuple_items[1].get("patternProperties").is_none());
    }

    #[test]
    fn to_openai_tools_strict_mode_applied_by_default() {
        let tools = vec![serde_json::json!({
            "name": "create_file",
            "description": "Create a file",
            "parameters": {
                "type": "object",
                "properties": {
                    "path": { "type": "string" },
                    "content": { "type": "string" },
                    "overwrite": { "type": "boolean" }
                },
                "required": ["path"]
            }
        })];

        let converted = to_openai_tools(&tools, true);
        assert_eq!(converted.len(), 1);

        let func = &converted[0]["function"];
        assert_eq!(func["strict"], true);
        assert_eq!(func["parameters"]["additionalProperties"], false);

        // All properties must be in the required array.
        let Some(required) = func["parameters"]["required"].as_array() else {
            panic!("required should be an array");
        };
        let required_names: Vec<&str> = required.iter().filter_map(|v| v.as_str()).collect();
        assert!(required_names.contains(&"path"));
        assert!(required_names.contains(&"content"));
        assert!(required_names.contains(&"overwrite"));
    }

    #[test]
    fn to_openai_tools_non_strict_skips_patching() {
        let tools = vec![serde_json::json!({
            "name": "create_file",
            "description": "Create a file",
            "parameters": {
                "type": "object",
                "properties": {
                    "path": { "type": "string" },
                    "content": { "type": "string" },
                    "overwrite": { "type": "boolean" }
                },
                "required": ["path"]
            }
        })];

        let converted = to_openai_tools(&tools, false);
        assert_eq!(converted.len(), 1);

        let func = &converted[0]["function"];
        assert_eq!(func["strict"], false);

        // strict-mode patching must NOT have run: no additionalProperties
        // and no array-form nullable types like ["boolean","null"].
        let serialized = func["parameters"].to_string();
        assert!(
            !serialized.contains("additionalProperties"),
            "strict mode should not inject additionalProperties: {serialized}"
        );
        assert!(
            !serialized.contains("[\"boolean\""),
            "strict mode should not produce array-form types: {serialized}"
        );
        assert!(
            !serialized.contains("[\"string\""),
            "strict mode should not produce array-form types: {serialized}"
        );
    }

    #[test]
    fn to_openai_tools_non_strict_complex_cron_like_schema() {
        // Schema modeled after the cron tool's `job` property: nested objects,
        // optional booleans, enum fields — the shapes that trigger Google's
        // INVALID_ARGUMENT when strict-mode array types are present.
        let tools = vec![serde_json::json!({
            "name": "schedule_cron",
            "description": "Schedule a cron job",
            "parameters": {
                "type": "object",
                "properties": {
                    "name": { "type": "string" },
                    "job": {
                        "type": "object",
                        "properties": {
                            "enabled": { "type": "boolean" },
                            "schedule": { "type": "string" },
                            "retry": { "type": "boolean" },
                            "mode": {
                                "type": "string",
                                "enum": ["once", "recurring"]
                            },
                            "config": {
                                "type": "object",
                                "properties": {
                                    "timeout": { "type": "integer" },
                                    "verbose": { "type": "boolean" }
                                },
                                "required": ["timeout"]
                            }
                        },
                        "required": ["schedule"]
                    }
                },
                "required": ["name", "job"]
            }
        })];

        let converted = to_openai_tools(&tools, false);
        let func = &converted[0]["function"];
        assert_eq!(func["strict"], false);

        // No array-form types anywhere in the output.
        let serialized = func["parameters"].to_string();
        // Array-form types look like `["boolean","null"]` — must not appear.
        assert!(
            !serialized.contains("[\"boolean\""),
            "should not contain array-form types: {serialized}"
        );
        assert!(
            !serialized.contains("[\"string\""),
            "should not contain array-form types: {serialized}"
        );
        assert!(
            !serialized.contains("[\"integer\""),
            "should not contain array-form types: {serialized}"
        );

        // Original required arrays preserved.
        let Some(job_required) = func["parameters"]["properties"]["job"]["required"].as_array()
        else {
            panic!("job required should be an array");
        };
        assert_eq!(job_required.len(), 1);
        assert_eq!(job_required[0], "schedule");

        // Nested object required array also preserved.
        let Some(config_required) =
            func["parameters"]["properties"]["job"]["properties"]["config"]["required"].as_array()
        else {
            panic!("config required should be an array");
        };
        assert_eq!(config_required.len(), 1);
        assert_eq!(config_required[0], "timeout");
    }

    // ── strip_control_tokens ──────────────────────────────────────

    #[test]
    fn control_tokens_strips_eom() {
        assert_eq!(
            super::strip_control_tokens("Hello!<|eom|>"),
            "Hello!"
        );
    }

    #[test]
    fn control_tokens_strips_mid_text() {
        assert_eq!(
            super::strip_control_tokens("A<|some_token|>B"),
            "AB"
        );
    }

    #[test]
    fn control_tokens_preserves_non_token() {
        let input = "Use <|not a token|> here";
        assert_eq!(super::strip_control_tokens(input), input);
    }

    #[test]
    fn control_tokens_pure_token_chunk() {
        // Entire chunk is a control token — result should be empty.
        assert_eq!(super::strip_control_tokens("<|eom|>"), "");
    }

    #[test]
    fn control_tokens_no_match() {
        assert_eq!(super::strip_control_tokens("normal text"), "normal text");
    }
}

